15	`include "axi/typedef.svh"
16	`include "axi/assign.svh"
17	
18	module tb_axi_serializer #(
19	    parameter int unsigned NoWrites = 5000,  // How many writes per master
20	    parameter int unsigned NoReads  = 3000   // How many reads per master
21	  );
22	  // Random master no Transactions
23	  localparam int unsigned NoPendingDut = 4;
24	  // Random Master Atomics
25	  localparam int unsigned MaxAW      = 32'd30;
26	  localparam int unsigned MaxAR      = 32'd30;
27	  localparam bit          EnAtop     = 1'b1;
28	  // timing parameters
29	  localparam time CyclTime = 10ns;
30	  localparam time ApplTime =  2ns;
31	  localparam time TestTime =  8ns;
32	  // AXI configuration
33	  localparam int unsigned AxiIdWidth   =  4;
34	  localparam int unsigned AxiAddrWidth =  32;    // Axi Address Width
35	  localparam int unsigned AxiDataWidth =  64;    // Axi Data Width
36	  localparam int unsigned AxiUserWidth =  5;
37	  // Sim print config, how many transactions
38	  localparam int unsigned PrintTxn = 500;
39	
40	  typedef axi_test::axi_rand_master #(
41	    // AXI interface parameters
42	    .AW ( AxiAddrWidth ),
43	    .DW ( AxiDataWidth ),
44	    .IW ( AxiIdWidth   ),
45	    .UW ( AxiUserWidth ),
46	    // Stimuli application and test time
47	    .TA ( ApplTime ),
48	    .TT ( TestTime ),
49	    // Maximum number of read and write transactions in flight
50	    .MAX_READ_TXNS  ( MaxAR  ),
51	    .MAX_WRITE_TXNS ( MaxAW  ),
52	    .AXI_ATOPS      ( EnAtop )
53	  ) axi_rand_master_t;
54	  typedef axi_test::axi_rand_slave #(
55	    // AXI interface parameters
56	    .AW ( AxiAddrWidth ),
57	    .DW ( AxiDataWidth ),
58	    .IW ( AxiIdWidth   ),
59	    .UW ( AxiUserWidth ),
60	    // Stimuli application and test time
61	    .TA ( ApplTime ),
62	    .TT ( TestTime )
63	  ) axi_rand_slave_t;
64	
65	  // -------------
66	  // DUT signals
67	  // -------------
68	  logic clk;
69	  logic rst_n;
70	  logic end_of_sim;
71	
72	  // interfaces
73	  AXI_BUS #(
74	    .AXI_ADDR_WIDTH ( AxiAddrWidth ),
75	    .AXI_DATA_WIDTH ( AxiDataWidth ),
76	    .AXI_ID_WIDTH   ( AxiIdWidth   ),
77	    .AXI_USER_WIDTH ( AxiUserWidth )
78	  ) master ();
79	  AXI_BUS_DV #(
80	    .AXI_ADDR_WIDTH ( AxiAddrWidth ),
81	    .AXI_DATA_WIDTH ( AxiDataWidth ),
82	    .AXI_ID_WIDTH   ( AxiIdWidth   ),
83	    .AXI_USER_WIDTH ( AxiUserWidth )
84	  ) master_dv (clk);
85	  AXI_BUS #(
86	    .AXI_ADDR_WIDTH ( AxiAddrWidth ),
87	    .AXI_DATA_WIDTH ( AxiDataWidth ),
88	    .AXI_ID_WIDTH   ( AxiIdWidth   ),
89	    .AXI_USER_WIDTH ( AxiUserWidth )
90	  ) slave ();
91	  AXI_BUS_DV #(
92	    .AXI_ADDR_WIDTH ( AxiAddrWidth ),
93	    .AXI_DATA_WIDTH ( AxiDataWidth ),
94	    .AXI_ID_WIDTH   ( AxiIdWidth   ),
95	    .AXI_USER_WIDTH ( AxiUserWidth )
96	  ) slave_dv (clk);
97	
98	  `AXI_ASSIGN(master, master_dv)
99	  `AXI_ASSIGN(slave_dv, slave)
100	
101	  //-----------------------------------
102	  // Clock generator
103	  //-----------------------------------
104	  clk_rst_gen #(
105	    .ClkPeriod    ( CyclTime ),
106	    .RstClkCycles ( 5        )
107	  ) i_clk_gen (
108	    .clk_o (clk),
109	    .rst_no(rst_n)
110	  );
111	
112	  //-----------------------------------
113	  // DUT
114	  //-----------------------------------
115	  axi_serializer_intf #(
116	    .MAX_READ_TXNS  ( NoPendingDut ),
117	    .MAX_WRITE_TXNS ( NoPendingDut ),
118	    .AXI_ID_WIDTH   ( AxiIdWidth   ), // AXI ID width
119	    .AXI_ADDR_WIDTH ( AxiAddrWidth ), // AXI address width
120	    .AXI_DATA_WIDTH ( AxiDataWidth ), // AXI data width
121	    .AXI_USER_WIDTH ( AxiUserWidth )  // AXI user width
122	  ) i_dut (
123	    .clk_i      ( clk      ), // clock
124	    .rst_ni     ( rst_n    ), // asynchronous reset active low
125	    .slv        ( master   ), // slave port
126	    .mst        ( slave    )  // master port
127	  );
128	
129	  initial begin : proc_axi_master
130	    automatic axi_rand_master_t axi_rand_master = new(master_dv);
131	    end_of_sim <= 1'b0;
132	    axi_rand_master.add_memory_region(32'h0000_0000, 32'h1000_0000, axi_pkg::DEVICE_NONBUFFERABLE);
133	    axi_rand_master.add_memory_region(32'h2000_0000, 32'h3000_0000, axi_pkg::WTHRU_NOALLOCATE);
134	    axi_rand_master.add_memory_region(32'h4000_0000, 32'h5000_0000, axi_pkg::WBACK_RWALLOCATE);
135	    axi_rand_master.reset();
136	    @(posedge rst_n);
137	    axi_rand_master.run(NoReads, NoWrites);
138	    end_of_sim <= 1'b1;
139	    repeat (100) @(posedge clk);
140	    $stop();
141	  end
142	
143	  initial begin : proc_axi_slave
144	    automatic axi_rand_slave_t  axi_rand_slave  = new(slave_dv);
145	    axi_rand_slave.reset();
146	    @(posedge rst_n);
147	    axi_rand_slave.run();
148	  end
149	
150	  // Checker
151	  typedef logic [AxiIdWidth-1:0]     axi_id_t;
152	  typedef logic [AxiAddrWidth-1:0]   axi_addr_t;
153	  typedef logic [AxiDataWidth-1:0]   axi_data_t;
154	  typedef logic [AxiDataWidth/8-1:0] axi_strb_t;
155	  typedef logic [AxiUserWidth-1:0]   axi_user_t;
156	  `AXI_TYPEDEF_AW_CHAN_T(aw_chan_t, axi_addr_t,  axi_id_t,  axi_user_t)
157	  `AXI_TYPEDEF_W_CHAN_T(w_chan_t,  axi_data_t,  axi_strb_t,  axi_user_t)
158	  `AXI_TYPEDEF_B_CHAN_T(b_chan_t,  axi_id_t,  axi_user_t)
159	  `AXI_TYPEDEF_AR_CHAN_T(ar_chan_t,  axi_addr_t,  axi_id_t,  axi_user_t)
160	  `AXI_TYPEDEF_R_CHAN_T(r_chan_t,  axi_data_t,  axi_id_t,  axi_user_t)
161	  axi_id_t  aw_queue[$];
162	  axi_id_t  ar_queue[$];
163	  aw_chan_t aw_chan[$];
164	  w_chan_t   w_chan[$];
165	  b_chan_t   b_chan[$];
166	  ar_chan_t ar_chan[$];
167	  r_chan_t   r_chan[$];
168	
169	  initial begin : proc_checker
170	    automatic axi_id_t  id_exp; // expected ID
171	    automatic aw_chan_t aw_exp; // expected AW
172	    automatic aw_chan_t aw_act; // actual AW
173	    automatic w_chan_t   w_exp; // expected W
174	    automatic w_chan_t   w_act; // actual W
175	    automatic b_chan_t   b_exp; // expected B
176	    automatic b_chan_t   b_act; // actual B
177	    automatic ar_chan_t ar_exp; // expected AR
178	    automatic ar_chan_t ar_act; // actual AR
179	    automatic r_chan_t   r_exp; // expected R
180	    automatic r_chan_t   r_act; // actual R
181	    forever begin
182	      @(posedge clk);
183	      #TestTime;
184	      // All FIFOs get populated if there is something to put in
185	      if (master.aw_valid && master.aw_ready) begin
186	        `AXI_SET_TO_AW(aw_exp, master)
187	        aw_exp.id = '0;
188	        id_exp    = master.aw_id;
189	        aw_chan.push_back(aw_exp);
190	        aw_queue.push_back(id_exp);
191	        if (master.aw_atop[axi_pkg::ATOP_R_RESP]) begin
192	          ar_queue.push_back(id_exp);
193	        end
194	      end
195	      if (master.w_valid && master.w_ready) begin
196	        `AXI_SET_TO_W(w_exp, master)
197	        w_chan.push_back(w_exp);
198	      end
199	      if (slave.b_valid && slave.b_ready) begin
200	        id_exp = aw_queue.pop_front();
201	        `AXI_SET_TO_B(b_exp, slave)
202	        b_exp.id = id_exp;
203	        b_chan.push_back(b_exp);
204	      end
205	      if (master.ar_valid && master.ar_ready) begin
206	        `AXI_SET_TO_AR(ar_exp, master)
207	        ar_exp.id = '0;
208	        id_exp    = master.ar_id;
209	        ar_chan.push_back(ar_exp);
210	        ar_queue.push_back(id_exp);
211	      end
212	      if (slave.r_valid && slave.r_ready) begin
213	        `AXI_SET_TO_R(r_exp, slave)
214	        if (slave.r_last) begin
215	          id_exp = ar_queue.pop_front();
216	        end else begin
217	          id_exp = ar_queue[0];
218	        end
219	        r_exp.id = id_exp;
220	        r_chan.push_back(r_exp);
221	      end
222	      // Check that all channels match the expected response
223	      if (slave.aw_valid && slave.aw_ready) begin
224	        aw_exp = aw_chan.pop_front();
225	        `AXI_SET_TO_AW(aw_act, slave)
